import javax.jws.WebMethod;
import javax.jws.WebService;
import java.util.HashMap;
import java.util.Map;

@WebService
public class EmployeeManagementService {

    private Map<String, Employee> employees = new HashMap<>();

    public EmployeeManagementService() {
        // Initialize with some sample data
        employees.put("1", new Employee("1", "John Doe", 50000));
        employees.put("2", new Employee("2", "Jane Smith", 60000));
    }

    @WebMethod
    public void updateSalary(String employeeId, double newSalary) {
        if (employees.containsKey(employeeId)) {
            Employee employee = employees.get(employeeId);
            employee.setSalary(newSalary);
        }
    }

    @WebMethod
    public void performReview(String employeeId, String review) {
        if (employees.containsKey(employeeId)) {
            Employee employee = employees.get(employeeId);
            employee.setPerformanceReview(review);
        }
    }

    @WebMethod
    public void terminateEmployee(String employeeId) {
        if (employees.containsKey(employeeId)) {
            employees.remove(employeeId);
        }
    }

    // Helper class to represent an Employee
    private static class Employee {
        private String id;
        private String name;
        private double salary;
        private String performanceReview;

        public Employee(String id, String name, double salary) {
            this.id = id;
            this.name = name;
            this.salary = salary;
        }

        // Getters and setters
        public String getId() { return id; }
        public void setId(String id) { this.id = id; }
        public String getName() { return name; }
        public void setName(String name) { this.name = name; }
        public double getSalary() { return salary; }
        public void setSalary(double salary) { this.salary = salary; }
        public String getPerformanceReview() { return performanceReview; }
        public void setPerformanceReview(String performanceReview) { this.performanceReview = performanceReview; }
    }

    // Main method to publish the service
    public static void main(String[] args) {
        EmployeeManagementService service = new EmployeeManagementService();
        javax.xml.ws.Endpoint.publish("http://localhost:8080/EmployeeManagement", service);
    }
}